21: public abstract class AbstractAspect {
22:     private final static org.slf4j.Logger log = LoggerFactory.getLogger(AbstractAspect.class);
23: 
24:     public Object aroundExecute(JoinPoint joinPoint) throws Throwable {
25:         TraceMessage traceMessage = LogMessageThreadLocal.logMessageThreadLocal.get();
26:         String traceId = TraceId.logTraceID.get();
27:         if (traceMessage == null) {
28:             traceMessage = new TraceMessage();
29:             traceMessage.getPositionNum().set(0);
30:         }
31:         traceMessage.setMessageType(joinPoint.getSignature().toString());
32:         traceMessage.setPosition(LogMessageConstant.TRACE_START);
33:         traceMessage.getPositionNum().incrementAndGet();
34:         LogMessageThreadLocal.logMessageThreadLocal.set(traceMessage);
35:         if (traceId != null) {
36:             log.info(LogMessageConstant.TRACE_PRE + GfJsonUtil.toJSONString(traceMessage));
37:         }
38:         Object proceed = ((ProceedingJoinPoint) joinPoint).proceed();
39:         traceMessage.setMessageType(joinPoint.getSignature().toString());
40:         traceMessage.setPosition(LogMessageConstant.TRACE_END);
41:         traceMessage.getPositionNum().incrementAndGet();
42:         if (traceId != null) {
43:             log.info(LogMessageConstant.TRACE_PRE + GfJsonUtil.toJSONString(traceMessage));
44:         }
45:         return proceed;
46:     }
