14: /**
15:  * {@link org.jboss.stdio.StdioContextSelector} and {@link org.jboss.logmanager.LogContextSelector}
16:  * that uses an {@link java.lang.InheritableThreadLocal} as a source of the contexts.
17:  * <p>
18:  * Note that if the logger is a CLI logger the default contexts will be used regardless of the thread-local contexts.
19:  * </p>
20:  *
21:  * @author Brian Stansberry (c) 2015 Red Hat Inc.
22:  */
23: class ThreadLocalContextSelector implements LogContextSelector, StdioContextSelector {
24: 
25:     private final InheritableThreadLocal<Contexts> threadLocal = new InheritableThreadLocal<>();
26: 
27:     private final Contexts localContexts;
28:     private final Contexts defaultContexts;
29:     private final ClassLoader cliClassLoader;
30: 
31:     ThreadLocalContextSelector(Contexts local, Contexts defaults) {
32:         assert local != null;
33:         assert local.getLogContext() != null; // local.stdioContext can be null
34:         assert defaults != null;
35:         assert defaults.getStdioContext() != null;
36:         assert defaults.getLogContext() != null;
37:         this.localContexts = local;
38:         this.defaultContexts = defaults;
39:         cliClassLoader = ThreadLocalContextSelector.class.getClassLoader();
40:     }
41: 
42:     Contexts pushLocal() {
43:         Contexts result = threadLocal.get();
44:         threadLocal.set(localContexts);
45:         return result;
46:     }
47: 
48:     void restore(Contexts toRestore) {
49:         threadLocal.set(toRestore);
50:     }
51: 
52:     @Override
53:     public StdioContext getStdioContext() {
54:         // CLI loggers should only use the default stdio context regardless if the thread-local context is set.
55:         final ClassLoader tccl = WildFlySecurityManager.getCurrentContextClassLoaderPrivileged();
56:         if (tccl != null && tccl.equals(cliClassLoader)) {
57:             return defaultContexts.getStdioContext();
58:         }
59:         Contexts threadContext = threadLocal.get();
60:         StdioContext local = threadContext != null ? threadContext.getStdioContext() : null;
61:         return local == null ? defaultContexts.getStdioContext() : local;
62:     }
63: 
64:     @Override
65:     public LogContext getLogContext() {
66:         // CLI loggers should only use the default stdio context regardless if the thread-local context is set This
67:         // allows the context configured for CLI, e.g. jboss-cli-logging.properties.
68:         final ClassLoader tccl = WildFlySecurityManager.getCurrentContextClassLoaderPrivileged();
69:         if (tccl != null && tccl.equals(cliClassLoader)) {
70:             return defaultContexts.getLogContext();
71:         }
72:         Contexts threadContext = threadLocal.get();
73:         LogContext local = threadContext != null ? threadContext.getLogContext() : null;
74:         return local == null ? defaultContexts.getLogContext() : local;
75:     }
76: 
77: }

