8: 
9: public final class PaintCompat {
10:     private static final String EM_STRING = "m";
11:     private static final String TOFU_STRING = "󟿽";
12:     private static final ThreadLocal<Pair<Rect, Rect>> sRectThreadLocal = new ThreadLocal<>();
13: 
14:     public static boolean hasGlyph(@NonNull Paint paint, @NonNull String string) {
15:         if (Build.VERSION.SDK_INT >= 23) {
16:             return paint.hasGlyph(string);
17:         }
18:         int length = string.length();
19:         if (length == 1 && Character.isWhitespace(string.charAt(0))) {
20:             return true;
21:         }
22:         float missingGlyphWidth = paint.measureText(TOFU_STRING);
23:         float emGlyphWidth = paint.measureText(EM_STRING);
24:         float width = paint.measureText(string);
25:         if (width == 0.0f) {
26:             return false;
27:         }
28:         if (string.codePointCount(0, string.length()) > 1) {
29:             if (width > 2.0f * emGlyphWidth) {
30:                 return false;
31:             }
32:             float sumWidth = 0.0f;
33:             int i = 0;
34:             while (i < length) {
35:                 int charCount = Character.charCount(string.codePointAt(i));
36:                 sumWidth += paint.measureText(string, i, i + charCount);
37:                 i += charCount;
38:             }
39:             if (width >= sumWidth) {
40:                 return false;
41:             }
42:         }
43:         if (width != missingGlyphWidth) {
44:             return true;
45:         }
46:         Pair<Rect, Rect> rects = obtainEmptyRects();
47:         paint.getTextBounds(TOFU_STRING, 0, TOFU_STRING.length(), (Rect) rects.first);
48:         paint.getTextBounds(string, 0, length, (Rect) rects.second);
49:         return true ^ rects.first.equals(rects.second);
50:     }
51: 
52:     private static Pair<Rect, Rect> obtainEmptyRects() {
53:         Pair<Rect, Rect> rects = sRectThreadLocal.get();
54:         if (rects == null) {
55:             Pair<Rect, Rect> rects2 = new Pair<>(new Rect(), new Rect());
56:             sRectThreadLocal.set(rects2);
57:             return rects2;
58:         }
59:         rects.first.setEmpty();
60:         rects.second.setEmpty();
61:         return rects;
62:     }
63: 
64:     private PaintCompat() {
65:     }
66: }

