29: /**
30:  * Copy of package-private
31:  * {@code org.springframework.boot.convert.CharSequenceToObjectConverter}, renamed for
32:  * differentiation.
33:  *
34:  * @author Phillip Webb
35:  * @author Andy Wilkinson
36:  */
37: final class ConfigurationPropertiesCharSequenceToObjectConverter implements ConditionalGenericConverter {
38: 
39: 	private static final TypeDescriptor STRING = TypeDescriptor.valueOf(String.class);
40: 
41: 	private static final TypeDescriptor BYTE_ARRAY = TypeDescriptor.valueOf(byte[].class);
42: 
43: 	private static final Set<ConvertiblePair> TYPES;
44: 
45: 	private final ThreadLocal<Boolean> disable = new ThreadLocal<>();
46: 
47: 	static {
48: 		TYPES = Collections.singleton(new ConvertiblePair(CharSequence.class, Object.class));
49: 	}
50: 
51: 	private final ConversionService conversionService;
52: 
53: 	ConfigurationPropertiesCharSequenceToObjectConverter(ConversionService conversionService) {
54: 		this.conversionService = conversionService;
55: 	}
56: 
57: 	@Override
58: 	public Set<ConvertiblePair> getConvertibleTypes() {
59: 		return TYPES;
60: 	}
61: 
62: 	@Override
63: 	public boolean matches(TypeDescriptor sourceType, TypeDescriptor targetType) {
64: 		if (sourceType.getType() == String.class || this.disable.get() == Boolean.TRUE) {
65: 			return false;
66: 		}
67: 		this.disable.set(Boolean.TRUE);
68: 		try {
69: 			boolean canDirectlyConvertCharSequence = this.conversionService.canConvert(sourceType, targetType);
70: 			if (canDirectlyConvertCharSequence && !isStringConversionBetter(sourceType, targetType)) {
71: 				return false;
72: 			}
73: 			return this.conversionService.canConvert(STRING, targetType);
74: 		}
75: 		finally {
76: 			this.disable.remove();
77: 		}
78: 	}
79: 
80: 	/**
81: 	 * Return if String based conversion is better based on the target type. This is
82: 	 * required when ObjectTo... conversion produces incorrect results.
83: 	 * @param sourceType the source type to test
84: 	 * @param targetType the target type to test
85: 	 * @return if string conversion is better
86: 	 */
87: 	private boolean isStringConversionBetter(TypeDescriptor sourceType, TypeDescriptor targetType) {
88: 		if (this.conversionService instanceof ApplicationConversionService applicationConversionService) {
89: 			if (applicationConversionService.isConvertViaObjectSourceType(sourceType, targetType)) {
90: 				// If an ObjectTo... converter is being used then there might be a
91: 				// better StringTo... version
92: 				return true;
93: 			}
94: 		}
95: 		// StringToArrayConverter / StringToCollectionConverter are better than
96: 		// ObjectToArrayConverter / ObjectToCollectionConverter
97: 		return (targetType.isArray() || targetType.isCollection()) && !targetType.equals(BYTE_ARRAY);
98: 	}
99: 
100: 	@Override
101: 	public @Nullable Object convert(@Nullable Object source, TypeDescriptor sourceType, TypeDescriptor targetType) {
102: 		if (source == null) {
103: 			return null;
104: 		}
105: 		return this.conversionService.convert(source.toString(), STRING, targetType);
106: 	}
107: 
108: }

