27: /**
28:  * 某一个数据源的事务管理器
29:  * @version : 2013-10-30
30:  * @author 赵永春 (zyc@hasor.net)
31:  */
32: public class TranManager extends DataSourceManager {
33:     private final static ThreadLocal<Map<DataSource, JdbcTransactionManager>> managerMap = ThreadLocal.withInitial(ConcurrentHashMap::new);
34:     private final static ThreadLocal<Map<DataSource, ConnectionHolder>>       currentMap = ThreadLocal.withInitial(ConcurrentHashMap::new);
35: 
36:     public static ConnectionHolder currentConnectionHolder(DataSource dataSource) {
37:         Objects.requireNonNull(dataSource);
38:         Map<DataSource, ConnectionHolder> localMap = currentMap.get();
39:         ConnectionHolder holder = localMap.get(dataSource);
40:         if (holder == null) {
41:             holder = localMap.putIfAbsent(dataSource, newConnectionHolder(dataSource));
42:             holder = localMap.get(dataSource);
43:         }
44:         return holder;
45:     }
46: 
47:     /** 该方法会拿到一个当前 Connection 的引用，在使用完毕之后必须要 close 它。否则会产生引用泄漏 */
48:     public static Connection currentConnection(DataSource dataSource) {
49:         ConnectionHolder holder = currentConnectionHolder(dataSource);
50:         return newProxyConnection(holder);
51:     }
52: 
53:     /** 改变当前{@link ConnectionHolder} */
54:     protected static void currentConnection(DataSource dataSource, ConnectionHolder holder) {
55:         Map<DataSource, ConnectionHolder> localMap = currentMap.get();
56:         if (holder == null) {
57:             localMap.remove(dataSource);
58:         } else {
59:             localMap.put(dataSource, holder);
60:         }
61:     }
62: 
63:     /** 获取事务管理器 */
64:     private static synchronized JdbcTransactionManager getTransactionManager(final DataSource dataSource) {
65:         Objects.requireNonNull(dataSource);
66:         Map<DataSource, JdbcTransactionManager> localMap = managerMap.get();
67:         JdbcTransactionManager manager = localMap.get(dataSource);
68:         if (manager == null) {
69:             manager = new JdbcTransactionManager(dataSource);
70:             localMap.put(dataSource, manager);
71:         }
72:         return manager;
73:     }
74: 
75:     /** 获取{@link TransactionManager} */
76:     public static synchronized TransactionManager getManager(DataSource dataSource) {
77:         return getTransactionManager(dataSource);
78:     }
79: 
80:     /** 获取{@link TransactionTemplate} */
81:     public static synchronized TransactionTemplate getTemplate(DataSource dataSource) {
82:         JdbcTransactionManager manager = getTransactionManager(dataSource);
83:         return manager.getTransactionTemplate();
84:     }
85: }

