33: /**
34:  * A singleton that can enqueue objects on a thread local for later retrieval in 
35:  * batch.
36:  */
37: public class ThreadLocalQueue {
38: 
39:     private static final ThreadLocalQueue INSTANCE = new ThreadLocalQueue();
40: 
41:     private static final ThreadLocal THREADLOCAL_QUEUE = new ThreadLocal();
42: 
43:     
44:     /**
45:      * @return The instance.
46:      */
47:     public static ThreadLocalQueue getInstance() {
48:         return INSTANCE;
49:     }
50:     
51:     /**
52:      * Private constructor for singleton.
53:      */
54:     private ThreadLocalQueue() {
55:     }
56:         
57:     /**
58:      * Enqueue an object on the thread local.
59:      * 
60:      * @param object The object.
61:      * @throws NullPointerException if the object is <code>null</code>.
62:      */
63:     public void enqueueObject(Object object) {
64:         if (object == null) {
65:             throw new NullPointerException("trying to enqueue null.");
66:         }
67:         
68:         List queue = (List)THREADLOCAL_QUEUE.get();
69:         
70:         if (queue == null) {
71:             queue = new LinkedList();
72:             THREADLOCAL_QUEUE.set(queue);
73:         }
74:         
75:         queue.add(object);
76:     }
77:     
78:     /**
79:      * Retrieve all the objects enqueued on the thread local.
80:      * 
81:      * @return A list containing the enqueued objects.
82:      */
83:     public List getEnqueuedObjects() {
84:         List queue = (List)THREADLOCAL_QUEUE.get();
85:         
86:         if (queue != null && !queue.isEmpty()) {
87:             return new ArrayList(queue);
88:         } else {
89:             return Collections.EMPTY_LIST;
90:         }
91:     }
