63: public class LastError extends NativeError {
64:   private static final long serialVersionUID = 1L;
65:   
66: 		final int code, kind;
67:     String description;
68:     
69:     static final int eLastErrorKindWindows = 1, eLastErrorKindCLibrary = 2;
70: 
71:     LastError(int code, int kind) {
72:         super(null);
73:         this.code = code;
74:         this.kind = kind;
75:         /*
76:         if (BridJ.verbose) {
77:             BridJ.info("Last error detected : " + getMessage());
78:         }*/
79:     }
80: 
81:     public int hashCode() {
82:     	return Integer.valueOf(code).hashCode() ^ Integer.valueOf(kind).hashCode();
83:     }
84: 
85:     public boolean equals(Object o) {
86:     	if (!(o instanceof LastError)) {
87:     		return false;
