100:     }
101: 
102:     /**
103:      * Native error description (as returned by <a
104:      * href="http://www.cplusplus.com/reference/clibrary/cstring/strerror/">strerror</a>
105:      * or <a
106:      * href="http://msdn.microsoft.com/en-us/library/ms680582(v=vs.85).aspx">FormatMessage</a>).
107:      */
108:     public String getDescription() {
109:     	if (description == null) {
110:     		description = getDescription(code, kind);
111:     	}
112:     	return description;
113:     }
114:     
115:     @Override
116:     public String getMessage() {
117:     	String description = getDescription();
118:     	return (description == null ? "?" : description.trim()) + " (error code = " + code + ")";
119:     }
120:     
121:     private static native String getDescription(int value, int kind);
122: 
123:     private static final ThreadLocal<LastError> lastError = new ThreadLocal<LastError>();
124: 
125:     public static LastError getLastError() {
126:         return lastError.get();
127:     }
128:     
129:     static LastError setLastError(int code, int kind) {
130:     		if (code == 0) {
131:     				lastError.set(null);
132:             return null;
133:         }
134:         LastError err = new LastError(code, kind);
135:         err.fillInStackTrace();
136:         lastError.set(err);
137:         return err;
138:     }
139: }

