122:      * Called before a method is called.
123:      * @param entry the entry point in the method for resume
124:      * @param numSlots the number of required stack slots for storing the state
125:      */
126:     public final void pushMethodAndReserveSpace(int entry, int numSlots) {
127:     	
128:     	
129:         final int methodIdx = methodTOS;
130:         
131:         
132:         if(method.length - methodIdx < 2) {
133:             growMethodStack();
134:         }
135:         
136:         int oldDataTos = method[methodIdx+1];
137:         curMethodSP = method[methodIdx-1];
138:         int dataTOS = curMethodSP + numSlots;
139:         
140:         method[methodIdx] = entry;
141:         method[methodIdx+1] = dataTOS;
142:         
143:         //maybe in the same method the previous suspendable invoke finished
144:         if (oldDataTos > dataTOS) {
145:         	for (int i = dataTOS; i < oldDataTos; i++) {
146:         		dataObject[i] = null;
147:         	}
148:         }
149:         
150:         if(dataTOS > dataObject.length) {
151:             growDataStack(dataTOS);
152:         }
153:     }
