33: public final class Utf8Utils {
34:     /**
35:      * Converts a string into its Java-style UTF-8 form. Java-style UTF-8
36:      * differs from normal UTF-8 in the handling of character '\0' and
37:      * surrogate pairs.
38:      *
39:      * @param string non-null; the string to convert
40:      * @return non-null; the UTF-8 bytes for it
41:      */
42:     public static byte[] stringToUtf8Bytes(String string) {
43:         int len = string.length();
44:         byte[] bytes = new byte[len * 3]; // Avoid having to reallocate.
45:         int outAt = 0;
46: 
47:         for (int i = 0; i < len; i++) {
48:             char c = string.charAt(i);
49:             if ((c != 0) && (c < 0x80)) {
50:                 bytes[outAt] = (byte) c;
51:                 outAt++;
52:             } else if (c < 0x800) {
53:                 bytes[outAt] = (byte) (((c >> 6) & 0x1f) | 0xc0);
54:                 bytes[outAt + 1] = (byte) ((c & 0x3f) | 0x80);
55:                 outAt += 2;
56:             } else {
57:                 bytes[outAt] = (byte) (((c >> 12) & 0x0f) | 0xe0);
58:                 bytes[outAt + 1] = (byte) (((c >> 6) & 0x3f) | 0x80);
59:                 bytes[outAt + 2] = (byte) ((c & 0x3f) | 0x80);
60:                 outAt += 3;
61:             }
62:         }
63: 
64:         byte[] result = new byte[outAt];
65:         System.arraycopy(bytes, 0, result, 0, outAt);
66:         return result;
67:     }
68: 
69:     private static final ThreadLocal<char[]> localBuffer =
70:             new ThreadLocal<char[]>() {
71:                 @Override
72:                 protected char[] initialValue() {
73:                     // A reasonably sized initial value
74:                     return new char[256];
75:                 }
76:             };
77: 
78:     /**
79:      * Converts an array of UTF-8 bytes into a string.
80:      *
81:      * @param bytes  non-null; the bytes to convert
82:      * @param start  the start index of the utf8 string to convert
83:      * @param length the length of the utf8 string to convert, not including any null-terminator that might be present
84:      * @return non-null; the converted string
85:      */
86:     public static String utf8BytesToString(byte[] bytes, int start, int length) {
87:         char[] chars = localBuffer.get();
88:         if (chars == null || chars.length < length) {
89:             chars = new char[length];
90:             localBuffer.set(chars);
91:         }
92:         int outAt = 0;
93: 
94:         for (int at = start; length > 0; /*at*/) {
95:             int v0 = bytes[at] & 0xFF;
96:             char out;
97:             switch (v0 >> 4) {
98:                 case 0x00:
99:                 case 0x01:
100:                 case 0x02:
101:                 case 0x03:
102:                 case 0x04:
103:                 case 0x05:
104:                 case 0x06:
105:                 case 0x07: {
106:                     // 0XXXXXXX -- single-byte encoding
107:                     length--;
108:                     if (v0 == 0) {
109:                         // A single zero byte is illegal.
110:                         return throwBadUtf8(v0, at);
111:                     }
112:                     out = (char) v0;
113:                     at++;
114:                     break;
115:                 }
116:                 case 0x0c:
117:                 case 0x0d: {
118:                     // 110XXXXX -- two-byte encoding
119:                     length -= 2;
120:                     if (length < 0) {
121:                         return throwBadUtf8(v0, at);
122:                     }
123:                     int v1 = bytes[at + 1] & 0xFF;
124:                     if ((v1 & 0xc0) != 0x80) {
125:                         return throwBadUtf8(v1, at + 1);
126:                     }
127:                     int value = ((v0 & 0x1f) << 6) | (v1 & 0x3f);
128:                     if ((value != 0) && (value < 0x80)) {
129:                         /*
130:                          * This should have been represented with
131:                          * one-byte encoding.
132:                          */
133:                         return throwBadUtf8(v1, at + 1);
134:                     }
135:                     out = (char) value;

